  ('social-worker-moex-01404', 'social-worker', 'social-worker-moex-109-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某位社工員想全盤有效了解轄區內多數少年的生活狀況，做為規劃新服務方案的參考。下列何種 抽樣方法可以獲得具有代表性的樣本，又可以在有限的時間內完成？', '["立意抽樣（purposivesampling）", "叢集抽樣（clustersampling）", "滾雪球抽樣（snowballsampling）", "簡單隨機抽樣（simplerandomsampling）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "3e07f321dfb8", "answer_pdf_sha1": "cf21ad8c6d04", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
